import java.io.*;
import org.apache.commons.text.StringEscapeUtils;

public class SecureXSSExample {

    public static void main(String[] args) {
        // Simulating user input from a form or user-controlled data
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly encoding user input to prevent XSS attacks
        String encodedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Creating a safe HTML output using the encoded user input
        String safeHtmlOutput = "<p>User Input: " + encodedUserInput + "</p>";

        try {
            // Writing the safe HTML output to a file
            FileWriter writer = new FileWriter("output.html");
            writer.write(safeHtmlOutput);
            writer.close();
            System.out.println("Safe HTML output generated successfully.");
        } catch (IOException e) {
            System.err.println("Error writing HTML output: " + e.getMessage());
        }
    }
}

